def word_frequency(text: str) -> dict[str, int]:
    if not text:
        return {}

    words = text.lower().split()
    for i in range(len(words)):
        words[i] = ''.join(char for char in words[i] if char.isalnum())

    frequency = {}
    for word in words:
        if word:
            frequency[word] = frequency.get(word, 0) + 1

    return frequency
